def assess(record: dict) -> str:
    required = {"adversarial", "case_id", "edge", "holdout", "normal", "rubric_levels", "slices", "tasks"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = sum(record["slices"].values()) == record["tasks"] and record["holdout"] > 0
    return "PASS" if ok else "REBUILD_EVAL_DATASET"

