elif "means_fraud" in invalid:
    invalid["means_fraud"] = True
elif "cache_authoritative" in invalid:
    invalid["cache_authoritative"] = True
    invalid["transactions"] = "cache"
elif "holdout" in invalid:
    invalid["holdout"] = 0
elif "jobs" in invalid:
    invalid["jobs"] = 0
elif "baseline_frozen" in invalid:
    invalid["baseline_frozen"] = False
elif "auto_fraud" in invalid:
    invalid["auto_fraud"] = True
elif "stages" in invalid:
    try:
        invalid["stages"] = list(reversed(list(invalid["stages"])))
    except Exception:
        pass
else:
    for k, v in list(invalid.items()):
        if k == "case_id":
            continue
        if isinstance(v, bool):
            invalid[k] = not v
            break
        if isinstance(v, (int, float)):
            invalid[k] = -1 if v != -1 else 0
            break
incomplete = {k: v for k, v in valid.items() if k != "holdout"}
print(assess(valid), assess(invalid), assess(incomplete))

